import React from 'react';
import { Link as RouterLink } from 'react-router-dom';
import { AppBar, Toolbar, Button, Box } from '@mui/material';

const Navbar = () => {
  const handleDownloadClick = () => {
    window.location.href = 'https://huggingface.co/hyonbokan/BGPStream13-10k-cutoff-1024-max-2048';
  };

  return (
    <AppBar position="static" sx={{ backgroundColor: '#2D3748', color: 'white' }}>
      <Toolbar>
        <Box sx={{ display: 'flex', flexGrow: 1, alignItems: 'center' }}>
          {/* Use MUI Button with RouterLink */}
          <Button 
            color="inherit" 
            component={RouterLink} 
            to="/" 
            sx={{
              color: 'inherit',
              '&:hover': {
                textDecoration: 'underline',
                backgroundColor: 'transparent', // Prevents MUI Button default hover background
              }
            }}
          >
            Home
          </Button>
          <Button 
            color="inherit" 
            component={RouterLink} 
            to="/dataset" 
            sx={{
              color: 'inherit',
              '&:hover': {
                textDecoration: 'underline',
                backgroundColor: 'transparent',
              }
            }}
          >
            Dataset
          </Button>
          <Button 
            color="inherit" 
            component={RouterLink} 
            to="/bgp_llama" 
            sx={{
              color: 'inherit',
              '&:hover': {
                textDecoration: 'underline',
                backgroundColor: 'transparent',
              }
            }}
          >
            BGP-LLaMA
          </Button>
        </Box>
        {/* The Button should open the link in a new tab */}
        <Button 
          color="primary" 
          variant="contained" 
          onClick={handleDownloadClick}
        >
          Download models
        </Button>
      </Toolbar>
    </AppBar>
  );
};

export default Navbar;
